// src/components/WeatherAnim.jsx
import React, { useMemo } from "react";

/**
 * WeatherAnim
 * Props:
 *  - climate: { tempC: number|null, humidity: number|null, rain?: number|null, updatedAt?: string }
 *
 * Simple inferred condition and CSS-driven animations.
 */
export default function WeatherAnim({ climate = {} }) {
  const cond = useMemo(() => {
    if (!climate) return "unknown";
    const rain = climate.rain ?? null;
    const t = typeof climate.tempC === "number" ? climate.tempC : null;
    const h = typeof climate.humidity === "number" ? climate.humidity : null;

    if (rain && rain > 0.1) return "rain";
    if (h !== null && h > 80 && t !== null && t <= 2) return "snow";
    // if humidity high and temp moderate -> cloudy
    if (h !== null && h > 70) return "cloudy";
    // if humidity moderate and temp warm -> partly-cloudy
    if (h !== null && h > 40 && h <= 70) return "partly-cloudy";
    // otherwise clear
    if (t !== null && t > 25 && (h === null || h < 60)) return "clear";
    // fallback
    return "partly-cloudy";
  }, [climate]);

  return (
    <div className={`weather-anim weather-${cond}`} aria-hidden>
      {/* Animated layers — purely CSS */}
      <div className="sun" />
      <div className="cloud cloud-a" />
      <div className="cloud cloud-b" />
      <div className="rain-layer">
        <div className="drop" />
        <div className="drop" />
        <div className="drop" />
      </div>
      <div className="snow-layer">
        <div className="flake" />
        <div className="flake" />
        <div className="flake" />
      </div>
    </div>
  );
}
